function handleInput(input: unknown): void {
  if (typeof input === 'string') {
    console.log(input.toUpperCase()); // narrowed to string
  }
}

function getUser(id: string): User | undefined {
  return users.find(u => u.id === id);
}

function getRequiredUser(id: string): User {
  const user = users.find(u => u.id === id);
  if (!user) throw new Error(`User ${id} not found`);
  return user;
}

const userName = user?.name ?? 'Anonymous';

function getFirst<T>(items: T[]): T | undefined {
  return items[0]; // correctly typed as T | undefined
}

function getFirstRequired<T>(items: T[]): T {
  const first = items[0];
  if (first === undefined) throw new Error('Array is empty');
  return first;
}

interface Config { timeout?: number }
const c1: Config = {};              // OK — omitted
// const c2: Config = { timeout: undefined }; // Error with exactOptionalPropertyTypes

interface ConfigExplicit { timeout?: number | undefined }
const c3: ConfigExplicit = { timeout: undefined }; // OK
